class Solution {
private:
    static bool isPalindrome(int num) {
        string s = to_string(num);
        string rev = s;
        reverse(rev.begin(), rev.end());
        return s == rev;
    }

    static bool isPrime(int m) {
        if (m <= 1) return false;
        if (m == 2) return true;
        if (m % 2 == 0) return false;
        for (int i = 3; i * i <= m; i += 2) {
            if (m % i == 0) {
                return false;
            }
        }
        return true;
    }

public:
    int primePalindrome(int n) {
        for (int m = n; ; ++m) {
            if (isPalindrome(m)) {
                if (m == 2) {
                    return 2;
                }
                if (m % 2 == 0) {
                    continue;
                }
                if (isPrime(m)) {
                    return m;
                }
            }
        }
    }
};

